public partial class BaseAreaRuntimeV3:Node
{
    private readonly Queue<string> _eventOrder=new();private readonly Dictionary<string,BaseSourceEventV3> _pendingEvents=new(StringComparer.Ordinal);private readonly Dictionary<Vector2I,HashSet<string>> _knownFloorsByChunk=new();private readonly HashSet<string> _knownStockpiles=new(StringComparer.Ordinal),_knownFarms=new(StringComparer.Ordinal);private BaseAreaSessionV3? _session;private CompanySessionV3? _companies;private ConstructionSessionV3? _construction;private StockpileSessionV3? _stockpiles;private FarmSessionV3? _farms;private RoomSessionV3? _rooms;private bool _initialized;
    public int PendingEventCount=>_pendingEvents.Count;
    public void Initialize(BaseAreaSessionV3 session,CompanySessionV3 companies,ConstructionSessionV3 construction,StockpileSessionV3 stockpiles,FarmSessionV3 farms,RoomSessionV3 rooms,Rect2I worldBounds)
    {
        if(_initialized)return;_initialized=true;_session=session;_companies=companies;_construction=construction;_stockpiles=stockpiles;_farms=farms;_rooms=rooms;session.SetWorldBounds(worldBounds);construction.Structures.StructureRegistered+=OnStructureRegistered;construction.Structures.StructureRemoved+=OnStructureRemoved;construction.Floors.ChunkChanged+=OnFloorChunkChanged;stockpiles.Zones.CellsChanged+=OnStockpileCellsChanged;farms.Plots.Changed+=OnFarmChanged;rooms.Registry.Remapped+=OnRoomsRemapped;session.Changed+=OnBaseChanged;QueueInitialSync();SetPhysicsProcess(true);
    }
    public override void _PhysicsProcess(double delta){if(!_initialized||_session==null||!GameplaySessionV3.IsCurrentBaseAreaSession(_session)){SetPhysicsProcess(false);return;}Stopwatch watch=Stopwatch.StartNew();_session.Diagnostics.ResetTick();ProcessEvents(BaseAreaSettingsV3.MaxDirtySourcesProcessedPerTick);_session.RebuildDirtyCompanies(BaseAreaSettingsV3.MaxBaseRebuildsPerTick);if(GameplaySessionV3.TryGetFacilityAffiliationSession(out FacilityAffiliationSessionV3? facilities)&&facilities!=null)facilities.ProcessDirty();if(GameplaySessionV3.TryGetMercenaryBaseAffiliationSession(out MercenaryBaseAffiliationSessionV3? mercenaryBases)&&mercenaryBases!=null)mercenaryBases.ProcessDirty();watch.Stop();_session.Diagnostics.RuntimeTickMs=watch.Elapsed.TotalMilliseconds;_session.Diagnostics.MaxRuntimeMs=Math.Max(_session.Diagnostics.MaxRuntimeMs,watch.Elapsed.TotalMilliseconds);}
