    public override void _ExitTree(){if(_construction!=null){_construction.Structures.StructureRegistered-=OnStructureRegistered;_construction.Structures.StructureRemoved-=OnStructureRemoved;_construction.Floors.ChunkChanged-=OnFloorChunkChanged;}if(_stockpiles!=null)_stockpiles.Zones.CellsChanged-=OnStockpileCellsChanged;if(_farms!=null)_farms.Plots.Changed-=OnFarmChanged;if(_rooms!=null)_rooms.Registry.Remapped-=OnRoomsRemapped;if(_session!=null)_session.Changed-=OnBaseChanged;_initialized=false;}
    private void QueueInitialSync(){if(_session==null||_construction==null||_stockpiles==null||_farms==null||_rooms==null||_companies==null)return;foreach(string id in _construction.Structures.GetAllStructureIds())if(_construction.Structures.TryGet(id,out var state)&&state!=null)Enqueue(StructureSource(state));foreach(Vector2I chunk in _construction.Floors.GetChunkCoords().ToList())QueueFloorChunk(chunk);foreach(string id in _stockpiles.Zones.GetAllZoneIds())if(_stockpiles.Zones.TryGetZone(id,out var zone)&&zone!=null){_knownStockpiles.Add(id);Enqueue(StockpileSource(zone));}foreach(var company in _companies.CompanyRegistry.GetAllCompanies())foreach(var plot in _farms.Plots.GetPlotsByCompany(company.CompanyId)){_knownFarms.Add(plot.FarmPlotId);Enqueue(FarmSource(plot));}_session.UpdateRoomSnapshot(_rooms.Registry.GetAllRooms());_session.Diagnostics.InitialSyncRemaining=_pendingEvents.Count;}
    private void ProcessEvents(int budget){if(_session==null)return;int processed=0;while(processed<budget&&_eventOrder.Count>0){string id=_eventOrder.Dequeue();if(!_pendingEvents.Remove(id,out BaseSourceEventV3 value))continue;if(value.Remove)_session.RemoveSource(value.SourceId);else if(value.Source!=null)_session.UpsertSource(value.Source);processed++;}_session.Diagnostics.SourceEventsProcessedThisTick=processed;_session.Diagnostics.InitialSyncProcessed+=processed;_session.Diagnostics.InitialSyncRemaining=_pendingEvents.Count;}
    private void Enqueue(BaseSpatialSourceV3 source){if(!_pendingEvents.ContainsKey(source.SourceId))_eventOrder.Enqueue(source.SourceId);_pendingEvents[source.SourceId]=new(false,source.SourceId,source);}
    private void EnqueueRemove(string id){if(!_pendingEvents.ContainsKey(id))_eventOrder.Enqueue(id);_pendingEvents[id]=new(true,id,null);}
    private BaseSpatialSourceV3 StructureSource(StructureStateV3 state){var classification=BaseSpatialSourceCatalogV3.ClassifyStructure(state.DefinitionId);long order=state.CompletedUtc.Ticks;return new(state.StructureId,state.CompanyId,classification.Kind,classification.Role,state.OccupiedCells,classification.Weight,order,order,true,true,state.DefinitionId);}
    private BaseSpatialSourceV3 FloorSource(FloorCellStateV3 floor){string id=FloorId(floor.Cell.Value);return new(id,floor.CompanyId,BaseSpatialSourceKindV3.Floor,BaseSpatialSourceRoleV3.Connector,new[]{floor.Cell},0,floor.CompletedSequence,floor.Revision,true,true,floor.FloorTypeId);}
    private BaseSpatialSourceV3 StockpileSource(StockpileZoneStateV3 zone){var role=BaseSpatialSourceCatalogV3.ClassifyStockpile(zone.Cells);return new(zone.StockpileZoneId,zone.CompanyId,BaseSpatialSourceKindV3.StockpileZone,role,zone.Cells,role==BaseSpatialSourceRoleV3.Anchor?3:0,zone.CreatedUtc.Ticks,_stockpiles?.Zones.Revision??0,true,zone.IsEnabled);}
    private BaseSpatialSourceV3 FarmSource(FarmPlotV3 plot){var role=BaseSpatialSourceCatalogV3.ClassifyFarm(plot.Cells.Select(c=>new GlobalCellCoord(c)).ToList());return new(plot.FarmPlotId,plot.CompanyId,BaseSpatialSourceKindV3.FarmPlot,role,plot.Cells.Select(c=>new GlobalCellCoord(c)),role==BaseSpatialSourceRoleV3.Anchor?2:0,plot.CreatedUtc.Ticks,plot.Revision,true,true,plot.CropDefinitionId);}
    private static string FloorId(Vector2I cell)=>$"basefloor:{cell.X}:{cell.Y}";
    private void OnStructureRegistered(StructureStateV3 state)=>Enqueue(StructureSource(state));private void OnStructureRemoved(StructureStateV3 state)=>EnqueueRemove(state.StructureId);
    private void OnFloorChunkChanged(Vector2I chunk,int count,long revision)=>QueueFloorChunk(chunk);
    private void QueueFloorChunk(Vector2I chunk){if(_construction==null)return;HashSet<string> current=new(StringComparer.Ordinal);foreach(var floor in _construction.Floors.EnumerateFloorsInChunk(chunk)){string id=FloorId(floor.Cell.Value);current.Add(id);Enqueue(FloorSource(floor));}if(_knownFloorsByChunk.TryGetValue(chunk,out var old))foreach(string id in old)if(!current.Contains(id))EnqueueRemove(id);if(current.Count==0)_knownFloorsByChunk.Remove(chunk);else _knownFloorsByChunk[chunk]=current;}
    private void OnStockpileCellsChanged(IReadOnlyList<GlobalCellCoord> cells){if(_stockpiles==null)return;HashSet<string> current=new(_stockpiles.Zones.GetAllZoneIds(),StringComparer.Ordinal);foreach(string id in _knownStockpiles)if(!current.Contains(id))EnqueueRemove(id);foreach(string id in current)if(_stockpiles.Zones.TryGetZone(id,out var zone)&&zone!=null)Enqueue(StockpileSource(zone));_knownStockpiles.Clear();_knownStockpiles.UnionWith(current);}
    private void OnFarmChanged(){if(_farms==null||_companies==null)return;HashSet<string> current=new(StringComparer.Ordinal);foreach(var company in _companies.CompanyRegistry.GetAllCompanies())foreach(var plot in _farms.Plots.GetPlotsByCompany(company.CompanyId)){current.Add(plot.FarmPlotId);Enqueue(FarmSource(plot));}foreach(string id in _knownFarms)if(!current.Contains(id))EnqueueRemove(id);_knownFarms.Clear();_knownFarms.UnionWith(current);}
    private void OnRoomsRemapped(RoomTopologyRemapV3 remap){if(_session!=null&&_rooms!=null)_session.UpdateRoomSnapshot(_rooms.Registry.GetAllRooms());}
    private void OnBaseChanged(BaseAreaChangeEventV3 value){}
}

public partial class BaseAreaOverlayV3:Node2D
{
    private BaseAreaSessionV3? _session;private BaseRoleSessionV3? _roles;private FacilityAffiliationSessionV3? _facilities;private MercenaryBaseAffiliationSessionV3? _mercenaryBases;private MercenarySessionV3? _mercenaries;private MercenaryViewRegistryV3? _views;private JobManagerV3? _jobs;private JobActivityRangePolicyV3? _policy;private WorldV2GridRenderer? _grid;private string _company=string.Empty;public bool OverlayEnabled{get;private set;}public int DrawnBaseCount{get;private set;}public int DrawnCellCount{get;private set;}public int DrawnActivityRangeCount{get;private set;}public int DrawnFacilityCount{get;private set;}public int DrawnMercenaryCount{get;private set;}public int DrawnPolicyMarkerCount{get;private set;}public int PerObjectNodeCount=>0;
