    public override void _Draw(){DrawnBaseCount=DrawnCellCount=DrawnActivityRangeCount=DrawnFacilityCount=DrawnMercenaryCount=DrawnPolicyMarkerCount=0;if(!OverlayEnabled||_session==null||_grid==null||!GameplaySessionV3.IsCurrentBaseAreaSession(_session))return;Transform2D inverse=GetViewport().GetCanvasTransform().AffineInverse();Vector2 size=GetViewportRect().Size;Vector2I minCell=_grid.WorldToCell(inverse*Vector2.Zero)-Vector2I.One,maxCell=_grid.WorldToCell(inverse*size)+Vector2I.One;Vector2I minChunk=BaseSpatialSourceV3.ChunkOf(minCell),maxChunk=BaseSpatialSourceV3.ChunkOf(maxCell);HashSet<string> ids=new(StringComparer.Ordinal),rangeIds=new(StringComparer.Ordinal),facilityIds=new(StringComparer.Ordinal);for(int y=minChunk.Y;y<=maxChunk.Y;y++)for(int x=minChunk.X;x<=maxChunk.X;x++){Vector2I chunk=new(x,y);foreach(string id in _session.Areas.GetIdsInChunk(chunk))ids.Add(id);if(_facilities!=null){foreach(string id in _facilities.GetActivityRangeChunkCandidates(_company,chunk))rangeIds.Add(id);foreach(var facility in _facilities.GetFacilitiesInChunk(chunk))if(facilityIds.Add(facility.FacilityKey))DrawFacility(facility,minCell,maxCell);}}foreach(string id in rangeIds.OrderBy(x=>x,StringComparer.Ordinal))if(_facilities?.TryGetActivityRange(id,out var range)==true&&range!=null){Color color=ColorFor(id);DrawRect(WorldRect(range.ExpandedBounds),new(color,.72f),false,2f);DrawnActivityRangeCount++;}foreach(string id in ids.OrderBy(x=>x,StringComparer.Ordinal))if(_session.Areas.TryGet(id,out var area)&&area!=null){Color color=ColorFor(id);Rect2I visible=area.Bounds.Intersection(new(minCell,maxCell-minCell+Vector2I.One));for(int y=visible.Position.Y;y<visible.End.Y;y++)for(int x=visible.Position.X;x<visible.End.X;x++)if(area.Contains(new(x,y))){DrawRect(new Rect2(x*_grid.TileSize,y*_grid.TileSize,_grid.TileSize,_grid.TileSize),new(color,.12f),true);DrawnCellCount++;}DrawRect(WorldRect(area.Bounds),new(color,.9f),false,1.5f);Vector2 center=_grid.CellToWorldCenter(area.CenterC