    private static string Short(string id)=>id.Length<=12?id:id[..12];private static Color ColorFor(string id){uint hash=2166136261;foreach(char c in id){hash^=c;hash*=16777619;}return Color.FromHsv((hash%360)/360f,.55f,.95f);}
